pub fn RECHARGEMETER(cpu: &mut Cpu) {
    cpu.reg.a = cpu.mem[sym::MaxKidStr];
    cpu.flags.c = true;
    let _r = (cpu.reg.a as u16) + (!cpu.mem[sym::KidStrength]) as u16 + (cpu.flags.c as u16);
    cpu.reg.a = _r as u8;
    cpu.flags.c = (_r >> 8) != 0;
    cpu.mem[sym::ChgKidStr] = cpu.reg.a;
    return;
}

pub fn BOOSTMETER(cpu: &mut Cpu) {
    cpu.reg.a = cpu.mem[sym::MaxKidStr];
    if cpu.reg.a >= 0x0a {
        RECHARGEMETER(cpu);
        return;
    }
    cpu.flags.c = false;
    let _r = (cpu.reg.a as u16) + (0x01) as u16 + (cpu.flags.c as u16);
    cpu.reg.a = _r as u8;
    cpu.flags.c = (_r >> 8) != 0;
    cpu.mem[sym::MaxKidStr] = cpu.reg.a;
    RECHARGEMETER(cpu);
    return;
}

pub fn GETOPDIST(cpu: &mut Cpu) {
    cpu.reg.a = cpu.mem[sym::CharScrn];
    if cpu.reg.a != cpu.mem[sym::OpScrn] {
        cpu.reg.x = 0x7f;
    } else {
        'b7: {
            cpu.reg.a = cpu.mem[sym::OpX];
            if cpu.reg.a >= cpu.mem[sym::CharX] {
                cpu.flags.c = true;
                let _r = (cpu.reg.a as u16) + (!cpu.mem[sym::CharX]) as u16 + (cpu.flags.c as u16);
                cpu.reg.a = _r as u8;
                cpu.flags.c = (_r >> 8) != 0;
                if (cpu.reg.a as i8) >= 0 {
                    break 'b7;
                } else {
                    cpu.reg.a = 0x7f;
                    if (cpu.reg.a as i8) >= 0 {
                        break 'b7;
                    }
                }
            }
            cpu.reg.a = cpu.mem[sym::CharX];
            cpu.flags.c = true;
            let _r = (cpu.reg.a as u16) + (!cpu.mem[sym::OpX]) as u16 + (cpu.flags.c as u16);
            cpu.reg.a = _r as u8;
            cpu.flags.c = (_r >> 8) != 0;
            if (cpu.reg.a as i8) < 0 {
                cpu.reg.a = 0x7f;
            }
            cpu.reg.a ^= 0xff;
            cpu.flags.c = false;
            let _r = (cpu.reg.a as u16) + (0x01) as u16 + (cpu.flags.c as u16);
            cpu.reg.a = _r as u8;
            cpu.flags.c = (_r >> 8) != 0;
        }
        cpu.reg.x = cpu.mem[sym::CharFace];
        if (cpu.reg.x as i8) < 0 {
            cpu.reg.a ^= 0xff;
            cpu.flags.c = false;
            let _r = (cpu.reg.a as u16) + (0x01) as u16 + (cpu.flags.c as u16);
            cpu.reg.a = _r as u8;
            cpu.flags.c = (_r >> 8) != 0;
        }
        cpu.reg.x = cpu.reg.a;
        cpu.reg.a = cpu.mem[sym::CharFace];
        cpu.reg.a ^= cpu.mem[sym::OpFace];
        if (cpu.reg.a as i8) < 0 {
            cpu.reg.a = cpu.reg.x;
            if cpu.reg.a < 0x72 {
                cpu.flags.c = false;
                let _r = (cpu.reg.a as u16) + (0x0d) as u16 + (cpu.flags.c as u16);
                cpu.reg.a = _r as u8;
                cpu.flags.c = (_r >> 8) != 0;
            }
            cpu.reg.x = cpu.reg.a;
            return;
        }
    }
    cpu.reg.a = cpu.reg.x;
    return;
}

pub fn UNEVENFLOOR(cpu: &mut Cpu) {
    crate::ext::getunderft(cpu);
    if cpu.reg.a != 0x05 {
        return;
    }
    cpu.mem[sym::CharY] = cpu.mem[sym::CharY].wrapping_add(1);
    return;
}
